import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import styled from 'styled-components';
import Container from '../components/common/Container';
import Button from '../components/common/Button';

const VerifyPage = () => {
  const { id } = useParams();
  const [testimonial, setTestimonial] = useState(null);
  const [isVerified, setIsVerified] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Simulate API call to fetch testimonial
    setTimeout(() => {
      setTestimonial({
        id,
        businessName: 'Coaching Business',
        original: 'The coaching was good. I learned some things that helped me.',
        enhanced: 'Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didnt just teach me tactics—it changed my entire mindset about whats possible.',
        clientName: 'John Doe',
      });
      setIsLoading(false);
    }, 1000);
  }, [id]);

  const handleVerify = () => {
    // Simulate API call to verify testimonial
    setIsVerified(true);
  };

  if (isLoading) {
    return (
      <Container>
        <VerifyContainer>
          <h2>Loading testimonial...</h2>
        </VerifyContainer>
      </Container>
    );
  }

  if (isVerified) {
    return (
      <Container>
        <VerifyContainer>
          <SuccessIcon>✓</SuccessIcon>
          <h2>Thank you for verifying!</h2>
          <p>Your testimonial has been approved and will help others make informed decisions.</p>
        </VerifyContainer>
      </Container>
    );
  }

  return (
    <Container>
      <VerifyContainer>
        <h2>{testimonial.businessName} would like you to verify your testimonial</h2>
        <p>Please review the enhanced version of your testimonial below:</p>

        <TestimonialComparison>
          <TestimonialBox>
            <h3>Your Original Words</h3>
            <TestimonialText>{testimonial.original}</TestimonialText>
          </TestimonialBox>

          <TestimonialBox enhanced>
            <h3>Enhanced Version</h3>
            <TestimonialText>{testimonial.enhanced}</TestimonialText>
          </TestimonialBox>
        </TestimonialComparison>

        <VerifyAction>
          <p>Does this enhanced version accurately represent your experience?</p>
          <VerifyButtons>
            <Button primary onClick={handleVerify}>Yes, I approve this testimonial</Button>
            <Button>No, this needs changes</Button>
          </VerifyButtons>
        </VerifyAction>
      </VerifyContainer>
    </Container>
  );
};

const VerifyContainer = styled.div`
  max-width: 800px;
  margin: 60px auto;
  text-align: center;
`;

const TestimonialComparison = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  margin: 40px 0;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const TestimonialBox = styled.div`
  padding: 24px;
  border-radius: 8px;
  background: ${props => props.enhanced ? '#ebf3ff' : '#f7f9fc'};
  text-align: left;

  h3 {
    margin-top: 0;
    margin-bottom: 16px;
    color: ${props => props.enhanced ? '#1a56db' : '#4a5568'};
  }
`;

const TestimonialText = styled.p`
  font-size: 16px;
  line-height: 1.6;
`;

const VerifyAction = styled.div`
  margin-top: 40px;

  p {
    margin-bottom: 20px;
  }
`;

const VerifyButtons = styled.div`
  display: flex;
  gap: 16px;
  justify-content: center;

  @media (max-width: 768px) {
    flex-direction: column;
    align-items: center;
  }
`;

const SuccessIcon = styled.div`
  font-size: 48px;
  width: 80px;
  height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #C6F6D5;
  color: #276749;
  border-radius: 50%;
  margin: 0 auto 24px;
`;

export default VerifyPage;
